request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?name ?type ?comment WHERE {
  ?elem a ?type .
  OPTIONAL { ?elem bbo:name ?name . }
  OPTIONAL { ?elem rdfs:comment ?comment . }
  OPTIONAL { ?elem tai:organizationId ?orgId . }
  FILTER(CONTAINS(STR(?elem), "4d36ddb24c9e4cc38572abbd646c1e58"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?org ?name ?label ?orgId ?comment WHERE {
  ?org a bboExt:Organization .
  OPTIONAL { ?org bbo:name ?name . }
  OPTIONAL { ?org rdfs:label ?label . }
  OPTIONAL { ?org tai:organizationId ?orgId . }
  OPTIONAL { ?org rdfs:comment ?comment . }
  FILTER(CONTAINS(LCASE(STR(?orgId)), "4d36ddb24c9e4cc38572abbd646c1e58") || CONTAINS(LCASE(STR(?org)), "4d36ddb24c9e4cc38572abbd646c1e58"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?created ?originalId WHERE {
  ?model a bboExt:Model .
  ?model tai:belongsTo ?org .
  ?org tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL { ?model tai:originalId ?originalId . }
}
LIMIT 25
